 78→  useEffect(() => {
 79→    const loadLeaderboard = async () => {
 80→      try {
 81→        setIsLoadingLeaderboard(true);
 82→        const data = await apiJson<LeaderboardEntry[]>('/api/leaderboard');
 83→        setLeaderboard(Array.isArray(data) ? data : []);
 84→      } catch {
 85→        setLeaderboard([]);
 86→      } finally {
 87→        setIsLoadingLeaderboard(false);
 88→      }
 89→    };
