189→    if (minutes < 60) return language === 'fr' ? `il y a ${minutes} min` : `${minutes}m ago`;
190→    const hours = Math.round(minutes / 60);
191→    if (hours < 24) return language === 'fr' ? `il y a ${hours}h` : `${hours}h ago`;
192→    const days = Math.round(hours / 24);
