 3→export async function GET(): Promise<Response> {
 4→  let dbStatus: "ok" | "error" = "error";
 5→  let httpStatus = 503;
 6→
 7→  try {
 8→    await query("SELECT 1");
 9→    dbStatus = "ok";
10→    httpStatus = 200;
11→  } catch {
12→    // db unreachable
13→  }
14→
15→  const body = JSON.stringify({ status: dbStatus === "ok" ? "ok" : "error", db: dbStatus, ts: new Date().toISOString() });
16→  return new Response(body, {
17→    status: httpStatus,
18→    headers: { "Content-Type": "application/json" },
19→  });
20→}
