 65→function parseLocation(input: unknown): SubmissionLocation | null {
 66→  if (!input || typeof input !== "object") return null;
 67→  const location = input as { latitude?: unknown; longitude?: unknown };
 68→  const latitude = typeof location.latitude === "string" ? Number(location.latitude) : (location.latitude as number);
 69→  const longitude = typeof location.longitude === "string" ? Number(location.longitude) : (location.longitude as number);
 70→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 71→  return { latitude, longitude };
 72→}
 73→
 74→function hasValue(input: unknown): boolean {
 75→  if (typeof input === "string") return Boolean(input.trim());
 76→  if (typeof input === "boolean") return true;
 77→  if (typeof input === "number") return Number.isFinite(input);
 78→  if (Array.isArray(input)) return input.length > 0;
 79→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 80→  return false;
 81→}
 82→
 83→function trimString(input: unknown, maxLen = 256): string | null {
 84→  if (typeof input !== "string") return null;
 85→  const value = input.trim();
 86→  if (!value) return null;
 87→  return value.slice(0, maxLen);
 88→}
 89→
 90→function sanitizeClientDevice(input: unknown): ClientDeviceInfo | null {
 91→  if (!input || typeof input !== "object") return null;
 92→  const raw = input as Record<string, unknown>;
 93→  const deviceId = trimString(raw.deviceId, 128);
 94→  if (!deviceId) return null;
 95→  const platform = trimString(raw.platform, 64);
 96→  const userAgent = trimString(raw.userAgent, 256);
 97→  const memory = typeof raw.deviceMemoryGb === "number" && Number.isFinite(raw.deviceMemoryGb) ? raw.deviceMemoryGb : null;
 98→  const cpu = typeof raw.hardwareConcurrency === "number" && Number.isFinite(raw.hardwareConcurrency) ? raw.hardwareConcurrency : null;
 99→  const isLowEnd = raw.isLowEnd === true;
100→
101→  return {
102→    deviceId,
103→    platform: platform ?? undefined,
104→    userAgent: userAgent ?? undefined,
105→    deviceMemoryGb: memory,
106→    hardwareConcurrency: cpu,
107→    isLowEnd,
108→  };
109→}
110→
111→function normalizeCategory(input: string | undefined): SubmissionCategory | null {
112→  if (!input) return null;
113→  const raw = input.trim();
114→  const resolved = normalizeCategoryAlias(raw);
115→  if (resolved && isValidCategory(resolved)) return resolved as SubmissionCategory;
116→  return null;
117→}
118→
119→function normalizeEventType(input: unknown): PointEventType {
120→  if (typeof input === "string" && allowedEventTypes.includes(input as PointEventType)) {
121→    return input as PointEventType;
122→  }
123→  return "CREATE_EVENT";
124→}
125→
126→function normalizeMapScope(input: string | null): MapScope {
127→  if (!input) return "bonamoussadi";
128→  const normalized = input.trim().toLowerCase();
129→  if (!allowedMapScopes.has(normalized as MapScope)) return "bonamoussadi";
130→  return normalized as MapScope;
131→}
