133→function stripBase64Prefix(imageBase64: string): string {
134→  const commaIndex = imageBase64.indexOf(",");
135→  return commaIndex === -1 ? imageBase64 : imageBase64.slice(commaIndex + 1);
136→}
137→
138→function isInlinePhotoData(value: unknown): value is string {
139→  return typeof value === "string" && value.startsWith(INLINE_PHOTO_PREFIX);
140→}
141→
142→function stripInlinePhotoData(event: PointEvent): PointEvent {
143→  if (!isInlinePhotoData(event.photoUrl)) return event;
144→  const { photoUrl: _photoUrl, ...rest } = event;
145→  const details = { ...(event.details ?? {}), hasPhoto: true };
146→  return { ...rest, details };
147→}
148→
149→function mimeToExtension(mime: string): string {
150→  switch (mime) {
151→    case "image/png":
152→      return "png";
153→    case "image/webp":
154→      return "webp";
155→    case "image/heic":
156→      return "heic";
157→    case "image/heif":
158→      return "heif";
159→    default:
160→      return "jpg";
161→  }
162→}
163→
164→function parseImagePayload(imageBase64: string): { imageBuffer: Buffer; mime: string; ext: string } | null {
165→  const match = imageBase64.match(INLINE_IMAGE_REGEX);
166→  if (!match) return null;
167→
168→  const mime = match[1]?.toLowerCase() ?? "";
169→  if (!allowedImageMime.has(mime)) return null;
170→
171→  const base64 = stripBase64Prefix(imageBase64);
172→  const imageBuffer = Buffer.from(base64, "base64");
173→  if (!imageBuffer.length) return null;
174→
175→  return { imageBuffer, mime, ext: mimeToExtension(mime) };
176→}
