195→function normalizeIp(raw: string | null): string | null {
196→  if (!raw) return null;
197→  const first = raw.split(",")[0]?.trim();
198→  if (!first) return null;
199→  const cleaned = first.replace(/^\[|\]$/g, "");
200→  if (cleaned.startsWith("::ffff:")) return cleaned.slice(7);
201→  if (/^\d+\.\d+\.\d+\.\d+:\d+$/.test(cleaned)) return cleaned.split(":")[0] ?? null;
202→  return cleaned;
203→}
204→
205→function isPrivateIp(ip: string): boolean {
206→  if (ip === "127.0.0.1" || ip === "::1") return true;
207→  if (ip.startsWith("10.")) return true;
208→  if (ip.startsWith("192.168.")) return true;
209→  if (ip.startsWith("172.")) {
210→    const second = Number(ip.split(".")[1]);
211→    if (second >= 16 && second <= 31) return true;
212→  }
213→  if (ip.startsWith("fc") || ip.startsWith("fd")) return true;
214→  if (ip.startsWith("fe80:")) return true;
215→  return false;
216→}
