218→interface IpApiResponse {
219→  latitude?: unknown;
220→  longitude?: unknown;
221→}
222→
223→async function fetchIpLocation(ip: string): Promise<SubmissionLocation | null> {
224→  const target = `https://ipapi.co/${ip}/json/`;
225→  const controller = new AbortController();
226→  const timeout = setTimeout(() => controller.abort(), 3000);
227→  try {
228→    const res = await fetch(target, { signal: controller.signal });
229→    if (!res.ok) return null;
230→    const data = (await res.json()) as IpApiResponse;
231→    const latitude = Number(data?.latitude);
232→    const longitude = Number(data?.longitude);
233→    if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
234→    return { latitude, longitude };
235→  } catch {
236→    return null;
237→  } finally {
238→    clearTimeout(timeout);
239→  }
240→}
