 28→function isUuid(input: string): boolean {
 29→  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(input);
 30→}
 31→
 32→function deterministicUuid(seed: string): string {
 33→  const hex = createHash("sha1").update(seed).digest("hex").slice(0, 32).split("");
 34→  hex[12] = "5";
 35→  const variant = parseInt(hex[16], 16);
 36→  hex[16] = ((variant & 0x3) | 0x8).toString(16);
 37→  return `${hex.slice(0, 8).join("")}-${hex.slice(8, 12).join("")}-${hex.slice(12, 16).join("")}-${hex.slice(16, 20).join("")}-${hex.slice(20, 32).join("")}`;
 38→}
