export async function insertSnapshotRows(rows: SnapshotRow[]): Promise<void> {
  // Bulk insert using a transaction
  await query("BEGIN");
  try {
    for (const row of rows) {
      await query(
        `INSERT INTO snapshots (snapshot_date, vertical_id, point_id, category, site_name, latitude, longitude, details, gaps, events_count, photo_url, source, external_id)
         VALUES ($1, $2, $3, $4, $5, $6, $7, $8::jsonb, $9, $10, $11, $12, $13)
         ON CONFLICT (snapshot_date, point_id) DO NOTHING`,
        [row.snapshot_date, row.vertical_id, row.point_id, row.category, row.site_name,
         row.latitude, row.longitude, JSON.stringify(row.details), row.gaps,
         row.events_count, row.photo_url, row.source, row.external_id]
      );
    }
    await query("COMMIT");
  } catch (err) {
    await query("ROLLBACK");
    throw err;
  }
}

