**Orchestration function** (also in `snapshotEngine.ts`):

```typescript
export async function runWeeklySnapshot(): Promise<{
  snapshotDate: string;
  pointCount: number;
  deltaCount: number;
  statsCount: number;
}> {
  const snapshotDate = new Date().toISOString().slice(0, 10); // "YYYY-MM-DD"

  // Step 1: Project all current state
  const allPoints = await buildCurrentProjection();
  const snapshotRows = buildSnapshotRows(snapshotDate, allPoints);

  // Step 2: Insert snapshot rows
  await insertSnapshotRows(snapshotRows);

  // Step 3: Find previous snapshot and compute deltas
  const previousDate = await getPreviousSnapshotDate(snapshotDate);
  let allDeltas: DeltaRow[] = [];
  if (previousDate) {
    const previousPoints = await getSnapshotPointsForDate(previousDate);
    const currentMap = new Map(snapshotRows.map(r => [r.point_id, r]));
    allDeltas = computeDeltas(snapshotDate, previousDate, currentMap, previousPoints);
    await insertDeltaRows(allDeltas);
  }

  // Step 4: Compute and insert stats per vertical
  let statsCount = 0;
  for (const verticalId of VERTICAL_IDS) {
    const verticalPoints = snapshotRows.filter(r => r.vertical_id === verticalId);
    const verticalDeltas = allDeltas.filter(d => d.vertical_id === verticalId);
    const historical = await getHistoricalStats(verticalId, 8);

    const totalPoints = verticalPoints.length;
    const completedPoints = verticalPoints.filter(p => p.gaps.length === 0).length;
    const completionRate = totalPoints > 0 ? completedPoints / totalPoints : 0;
    const avgEvents = totalPoints > 0
      ? verticalPoints.reduce((s, p) => s + p.events_count, 0) / totalPoints
      : 0;

    const newCount = verticalDeltas.filter(d => d.delta_type === "new").length;
    const removedCount = verticalDeltas.filter(d => d.delta_type === "removed").length;
    const changedCount = new Set(
      verticalDeltas.filter(d => d.delta_type === "changed").map(d => d.point_id)
    ).size;
    const unchangedCount = verticalDeltas.filter(d => d.delta_type === "unchanged").length;

    // Price average for fuel verticals
    let avgPrice: number | null = null;
    if (verticalId === "fuel_station" || verticalId === "fuel_fleet") {
      const prices = verticalPoints
        .map(p => (p.details as any)?.fuelPrice ?? (p.details as any)?.price)
        .filter((v): v is number => typeof v === "number" && Number.isFinite(v));
      avgPrice = prices.length > 0 ? prices.reduce((s, v) => s + v, 0) / prices.length : null;
    }

    // Historical values for z-score (from last 8 weeks)
    const historicalTotals = historical.map(h => h.total_points);
    const historicalNew = historical.map(h => h.new_count);
    const historicalRemoved = historical.map(h => h.removed_count);

    const prevTotal = historical[0]?.total_points ?? null;
    const wowGrowth = prevTotal && prevTotal > 0
      ? (totalPoints - prevTotal) / prevTotal
      : null;

    const movingAvg = computeMovingAverage(
      [...historicalTotals.reverse(), totalPoints],
      4
    );

    const anomalyFlags = [
      detectAnomalies(totalPoints, historicalTotals, "total_points"),
      detectAnomalies(newCount, historicalNew, "new_count"),
      detectAnomalies(removedCount, historicalRemoved, "removed_count"),
    ].filter((a): a is NonNullable<typeof a> => a !== null);

    const stats: StatsRow = {
      snapshot_date: snapshotDate,
      vertical_id: verticalId,
      total_points: totalPoints,
      completed_points: completedPoints,
      completion_rate: Math.round(completionRate * 10000) / 100,
      avg_events_per_point: Math.round(avgEvents * 100) / 100,
      new_count: newCount,
      removed_count: removedCount,
      changed_count: changedCount,
      unchanged_count: unchangedCount,
      avg_price: avgPrice,
      avg_confidence_score: null,
      week_over_week_growth: wowGrowth ? Math.round(wowGrowth * 10000) / 100 : null,
      moving_avg_4w: movingAvg,
      z_score_total_points: computeZScore(totalPoints, historicalTotals),
      z_score_new_count: computeZScore(newCount, historicalNew),
      z_score_removed_count: computeZScore(removedCount, historicalRemoved),
      anomaly_flags: anomalyFlags,
    };

    await insertStatsRow(stats);
    statsCount++;
  }

  return {
    snapshotDate,
    pointCount: snapshotRows.length,
    deltaCount: allDeltas.length,
    statsCount,
  };
}
