// api/cron/snapshot.ts
import { runWeeklySnapshot } from "../../lib/server/snapshotEngine.js";
import { jsonResponse, errorResponse } from "../../lib/server/http.js";

export async function GET(request: Request): Promise<Response> {
  // Verify cron secret
  const authHeader = request.headers.get("authorization");
  const cronSecret = process.env.CRON_SECRET;

  if (!cronSecret) {
    return errorResponse("CRON_SECRET not configured", 500);
  }

  if (authHeader !== `Bearer ${cronSecret}`) {
    return errorResponse("Unauthorized", 401);
  }

  try {
    const result = await runWeeklySnapshot();
    return jsonResponse({
      success: true,
      ...result,
    });
  } catch (error) {
    console.error("[CRON_SNAPSHOT_ERROR]", error);
    return errorResponse(
      error instanceof Error ? error.message : "Snapshot failed",
      500
    );
  }
}
